module watchdog_timer(  
    input wire clk,  
    input wire update,  
    input wire [3:0] timeout,  
    output reg reset  
);  
    reg [3:0] remaining_time;  

    always @(posedge clk) begin  
        if (update)  
            remaining_time <= timeout;  
        else if (remaining_time > 0)  
            remaining_time <= remaining_time - 1;  

        reset <= (remaining_time == 0);  
    end  
endmodule
